		}
	}

	pairU := make([]int, nLeft)
	pairV := make([]int, nRight)
	dist := make([]int, nLeft+1)

	for i := range pairU {
		pairU[i] = -1
	}
	for i := range pairV {
		pairV[i] = -1
	}

	var bfs func() bool
	bfs = func() bool {
		q := []int{}
		for u := 0; u < nLeft; u++ {
			if pairU[u] == -1 {
				dist[u] = 0
				q = append(q, u)
			} else {
				dist[u] = math.MaxInt32
			}
		}
		dist[nLeft] = math.MaxInt32

		for len(q) > 0 {
			u := q[0]
			q = q[1:]

			if dist[u] < dist[nLeft] {
