					pu := pairV[v]
					if pu == -1 {
						if dist[nLeft] == math.MaxInt32 {
							dist[nLeft] = dist[u] + 1
						}
					} else if dist[pu] == math.MaxInt32 {
						dist[pu] = dist[u] + 1
						q = append(q, pu)
					}
				}
			}
		}
		return dist[nLeft] != math.MaxInt32
	}

	var dfs func(int) bool
	dfs = func(u int) bool {
		if u != -1 {
