    for (i <- 0 until m) {
      val u = arr(3 + 2 * i)
      val v = arr(3 + 2 * i + 1)
      if (u >= 0 && u < nLeft && v >= 0 && v < nRight) {
        adj(u).append(v)
      }
    }

    val pairU = Array.fill(nLeft)(-1)
    val pairV = Array.fill(nRight)(-1)
    val dist = new Array[Int](nLeft + 1)

    def bfs(): Boolean = {
      val q: Queue[Int] = new LinkedList()
      for (u <- 0 until nLeft) {
        if (pairU(u) == -1) {
          dist(u) = 0
          q.add(u)
        } else {
          dist(u) = Int.MaxValue
        }
      }

      dist(nLeft) = Int.MaxValue

      while (!q.isEmpty) {
        val u = q.poll()

        if (dist(u) < dist(nLeft)) {
          for (v <- adj(u)) {
            val pu = pairV(v)
            if (pu == -1) {
              if (dist(nLeft) == Int.MaxValue) {
                dist(nLeft) = dist(u) + 1
              }
            } else if (dist(pu) == Int.MaxValue) {
              dist(pu) = dist(u) + 1
              q.add(pu)
            }
          }
        }
      }

      dist(nLeft) != Int.MaxValue
    }

    def dfs(u: Int): Boolean = {
      if (u != -1) {
        for (v <- adj(u)) {
          val pu = pairV(v)
          if (pu == -1 || (dist(pu) == dist(u) + 1 && dfs(pu))) {
            pairV(v) = u
            pairU(u) = v
            return true
          }
        }
        dist(u) = Int.MaxValue
        return false
      }
      true
    }

    var matching = 0
    while (bfs()) {
      for (u <- 0 until nLeft) {
        if (pairU(u) == -1 && dfs(u)) {
          matching += 1
        }
      }
    }

    matching
  }
}

import Foundation

class BipartiteMatching {
    static func solve(_ arr: [Int]) -> Int {
        if arr.count < 3 { return 0 }

        let nLeft = arr[0]
        let nRight = arr[1]
        let m = arr[2]

        if arr.count < 3 + 2 * m { return 0 }
        if nLeft == 0 || nRight == 0 { return 0 }

        var adj = [[Int]](repeating: [], count: nLeft)
        for i in 0..<m {
            let u = arr[3 + 2 * i]
            let v = arr[3 + 2 * i + 1]
            if u >= 0 && u < nLeft && v >= 0 && v < nRight {
                adj[u].append(v)
            }
        }

        var pairU = [Int](repeating: -1, count: nLeft)
        var pairV = [Int](repeating: -1, count: nRight)
        var dist = [Int](repeating: 0, count: nLeft + 1)

        func bfs() -> Bool {
            var q = [Int]()
            for u in 0..<nLeft {
                if pairU[u] == -1 {
                    dist[u] = 0
                    q.append(u)
                } else {
                    dist[u] = Int.max
                }
            }

            dist[nLeft] = Int.max

            var head = 0
            while head < q.count {
                let u = q[head]
                head += 1

                if dist[u] < dist[nLeft] {
                    for v in adj[u] {
                        let pu = pairV[v]
                        if pu == -1 {
                            if dist[nLeft] == Int.max {
                                dist[nLeft] = dist[u] + 1
                            }
                        } else if dist[pu] == Int.max {
                            dist[pu] = dist[u] + 1
                            q.append(pu)
                        }
                    }
                }
            }

            return dist[nLeft] != Int.max
        }

        func dfs(_ u: Int) -> Bool {
            if u != -1 {
                for v in adj[u] {
                    let pu = pairV[v]
                    if pu == -1 || (dist[pu] == dist[u] + 1 && dfs(pu)) {
                        pairV[v] = u
                        pairU[u] = v
                        return true
                    }
                }
                dist[u] = Int.max
                return false
            }
            return true
        }

        var matching = 0
        while bfs() {
            for u in 0..<nLeft {
                if pairU[u] == -1 && dfs(u) {
                    matching += 1
                }
            }
        }

        return matching
    }
}

export function hopcroftKarp(arr: number[]): number {
  if (arr.length < 3) return 0;

  const nLeft = arr[0];
  const nRight = arr[1];
  const m = arr[2];

  if (arr.length < 3 + 2 * m) return 0;
  if (nLeft === 0 || nRight === 0) return 0;

  const adj: number[][] = Array.from({ length: nLeft }, () => []);
  for (let i = 0; i < m; i++) {
    const u = arr[3 + 2 * i];
    const v = arr[3 + 2 * i + 1];
    if (u >= 0 && u < nLeft && v >= 0 && v < nRight) {
      adj[u].push(v);
    }
  }

  const pairU: number[] = new Array(nLeft).fill(-1);
  const pairV: number[] = new Array(nRight).fill(-1);
  const dist: number[] = new Array(nLeft + 1).fill(0);

  function bfs(): boolean {
    const q: number[] = [];
    for (let u = 0; u < nLeft; u++) {
      if (pairU[u] === -1) {
        dist[u] = 0;
        q.push(u);
      } else {
        dist[u] = Number.MAX_SAFE_INTEGER;
      }
    }

    dist[nLeft] = Number.MAX_SAFE_INTEGER;

    let head = 0;
    while (head < q.length) {
      const u = q[head++];

      if (dist[u] < dist[nLeft]) {
        for (const v of adj[u]) {
          const pu = pairV[v];
          if (pu === -1) {
            if (dist[nLeft] === Number.MAX_SAFE_INTEGER) {
              dist[nLeft] = dist[u] + 1;
            }
          } else if (dist[pu] === Number.MAX_SAFE_INTEGER) {
            dist[pu] = dist[u] + 1;
            q.push(pu);
          }
        }
      }
    }

    return dist[nLeft] !== Number.MAX_SAFE_INTEGER;
  }

  function dfs(u: number): boolean {
    if (u !== -1) {
      for (const v of adj[u]) {
        const pu = pairV[v];
        if (pu === -1 || (dist[pu] === dist[u] + 1 && dfs(pu))) {
          pairV[v] = u;
          pairU[u] = v;
          return true;
        }
      }
      dist[u] = Number.MAX_SAFE_INTEGER;
      return false;
    }
    return true;
  }

  let matching = 0;
  while (bfs()) {
    for (let u = 0; u < nLeft; u++) {
      if (pairU[u] === -1 && dfs(u)) {
        matching++;
      }
    }
  }

  return matching;
}

/**
 * Hopcroft-Karp: Maximum bipartite matching in O(E * sqrt(V)).
 */
export function hopcroftKarp(numLeft: number, numRight: number, edges: [number, number][]): number {
    const adj: number[][] = Array.from({ length: numLeft }, () => []);
    for (const [u, v] of edges) {
        adj[u].push(v);
    }

    const matchLeft = new Array(numLeft).fill(-1);
    const matchRight = new Array(numRight).fill(-1);
    const dist = new Array(numLeft).fill(0);
    const INF = Number.MAX_SAFE_INTEGER;

    function bfs(): boolean {
        const queue: number[] = [];
        for (let u = 0; u < numLeft; u++) {
            if (matchLeft[u] === -1) {
                dist[u] = 0;
                queue.push(u);
            } else {
                dist[u] = INF;
            }
        }
        let found = false;
        let front = 0;
        while (front < queue.length) {
            const u = queue[front++];
            for (const v of adj[u]) {
                const nextU = matchRight[v];
                if (nextU === -1) {
                    found = true;
                } else if (dist[nextU] === INF) {
                    dist[nextU] = dist[u] + 1;
                    queue.push(nextU);
                }
            }
        }
        return found;
    }

    function dfs(u: number): boolean {
        for (const v of adj[u]) {
            const nextU = matchRight[v];
            if (nextU === -1 || (dist[nextU] === dist[u] + 1 && dfs(nextU))) {
                matchLeft[u] = v;
                matchRight[v] = u;
                return true;
            }
        }
        dist[u] = INF;
        return false;
    }

    let matching = 0;
    while (bfs()) {
        for (let u = 0; u < numLeft; u++) {
            if (matchLeft[u] === -1 && dfs(u)) {
                matching++;
            }
        }
    }
    return matching;
}

